import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart'; import 'package:integration_test/integration_test.dart';  /// E2E tests for vote casting: navigate to election, select option, submit vote, /// verify VP or ticket notification. Used by CI for critical user flow validation. void main() {   IntegrationTestWidgetsFlutterBinding.ensureInitialized();    group('Vote Casting E2E', () {     testWidgets('User can cast vote in election', (tester) async {       await tester.pumpAndSettle(const Duration(seconds: 3));        final electionCard = find.byKey(const Key('election_card_0'));       if (electionCard.evaluate().isNotEmpty) {         await tester.tap(electionCard);         await tester.pumpAndSettle(const Duration(seconds: 2));       }        final voteButton = find.byKey(const Key('vote_button'));       if (voteButton.evaluate().isNotEmpty) {         await tester.tap(voteButton);         await tester.pumpAndSettle(const Duration(seconds: 2));       }        final option = find.byKey(const Key('vote_option_0'));       if (option.evaluate().isNotEmpty) {         await tester.tap(option);         await tester.pumpAndSettle();       }        final submitButton = find.byKey(const Key('submit_vote_button'));       if (submitButton.evaluate().isNotEmpty) {         await tester.tap(submitButton);         await tester.pumpAndSettle(const Duration(seconds: 3));       }        final successMessage = find.textContaining('VP');       final ticketPopup = find.textContaining('Ticket');       expect(         successMessage.evaluate().isNotEmpty || ticketPopup.evaluate().isNotEmpty,         isTrue,         reason: 'Should show VP earned or ticket notification after voting',       );     });   }); }
